import { createSlice } from '@reduxjs/toolkit';
import {
  fetchFriends, fetchFriendRequests, fetchSentRequests,
  fetchSuggestions, sendFriendRequest, acceptFriendRequest,
  removeFriend, fetchFriendCount,
} from '../thunks/friendThunks';

const initialState = {
  friends: [],
  requests: [],
  sentRequests: [],
  suggestions: [],
  friendCount: 0,
  loading: false,
  requestsLoading: false,
  hasMoreFriends: true,
  error: null,
};

const friendSlice = createSlice({
  name: 'friends',
  initialState,
  reducers: {
    resetFriends: () => initialState,
  },
  extraReducers: (builder) => {
    // Fetch friends
    builder
      .addCase(fetchFriends.pending, (state) => {
        state.loading = true;
      })
      .addCase(fetchFriends.fulfilled, (state, action) => {
        state.loading = false;
        const { friends, skip } = action.payload;
        if (skip === 0) {
          state.friends = friends;
        } else {
          state.friends = [...state.friends, ...friends];
        }
        state.hasMoreFriends = friends.length >= 20;
      })
      .addCase(fetchFriends.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    // Fetch requests
    builder
      .addCase(fetchFriendRequests.pending, (state) => {
        state.requestsLoading = true;
      })
      .addCase(fetchFriendRequests.fulfilled, (state, action) => {
        state.requestsLoading = false;
        const { requests, skip } = action.payload;
        if (skip === 0) {
          state.requests = requests;
        } else {
          state.requests = [...state.requests, ...requests];
        }
      })
      .addCase(fetchFriendRequests.rejected, (state) => {
        state.requestsLoading = false;
      });

    // Fetch sent requests
    builder
      .addCase(fetchSentRequests.fulfilled, (state, action) => {
        const { sent, skip } = action.payload;
        if (skip === 0) {
          state.sentRequests = sent;
        } else {
          state.sentRequests = [...state.sentRequests, ...sent];
        }
      });

    // Fetch suggestions
    builder
      .addCase(fetchSuggestions.fulfilled, (state, action) => {
        state.suggestions = action.payload;
      });

    // Send friend request
    builder
      .addCase(sendFriendRequest.fulfilled, (state, action) => {
        const friendId = action.payload;
        // Remove from suggestions if present
        state.suggestions = state.suggestions.filter((s) => s._id !== friendId);
      });

    // Accept/reject friend request
    builder
      .addCase(acceptFriendRequest.fulfilled, (state, action) => {
        const { friendId, accept } = action.payload;
        // Remove from requests
        state.requests = state.requests.filter((r) => {
          const rId = typeof r.userId === 'object' ? r.userId._id : r.userId;
          return rId !== friendId;
        });
        if (accept) {
          state.friendCount += 1;
        }
      });

    // Remove friend
    builder
      .addCase(removeFriend.fulfilled, (state, action) => {
        const friendId = action.payload;
        state.friends = state.friends.filter((f) => {
          const fId = typeof f.userId === 'object' ? f.userId._id : f.userId;
          return fId !== friendId;
        });
        state.friendCount = Math.max(0, state.friendCount - 1);
      });

    // Friend count
    builder
      .addCase(fetchFriendCount.fulfilled, (state, action) => {
        state.friendCount = typeof action.payload === 'number'
          ? action.payload
          : action.payload?.count || 0;
      });
  },
});

export const { resetFriends } = friendSlice.actions;
export default friendSlice.reducer;
