import { useState, useEffect, useCallback } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { getCallSocket, connectCallSocket } from '../api/callSocket';

const useIncomingCall = () => {
  const { isAuthenticated, user } = useSelector((state) => state.auth);
  const [incomingCall, setIncomingCall] = useState(null);
  const navigate = useNavigate();

  const handleIncomingOffer = useCallback((sdp, callType, callerName1, callerName2, callerID1, callerID2) => {
    // Only show if caller is not us
    if (callerID1 === user?._id) return;

    setIncomingCall({
      sdp,
      callType,
      callerName: callerName1 || 'Unknown',
      callerID: callerID1,
      recipientID: callerID2,
    });
  }, [user?._id]);

  useEffect(() => {
    if (!isAuthenticated || !user?._id) return;

    const socket = connectCallSocket();
    socket.on('onOffer', handleIncomingOffer);

    return () => {
      socket.off('onOffer', handleIncomingOffer);
    };
  }, [isAuthenticated, user?._id, handleIncomingOffer]);

  const acceptCall = useCallback(() => {
    if (!incomingCall) return;
    navigate(`/calls?recipientId=${incomingCall.callerID}&name=${encodeURIComponent(incomingCall.callerName)}&type=${incomingCall.callType}&who=receiver`);
    setIncomingCall(null);
  }, [incomingCall, navigate]);

  const declineCall = useCallback(() => {
    setIncomingCall(null);
  }, []);

  return { incomingCall, acceptCall, declineCall };
};

export default useIncomingCall;
