import { createAsyncThunk } from '@reduxjs/toolkit';
import chatService from '../../api/services/chatService';

export const fetchChatList = createAsyncThunk(
  'chat/fetchList',
  async (_, { rejectWithValue }) => {
    try {
      const response = await chatService.getChatList({});
      return response.data.data || response.data || [];
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to load chats');
    }
  }
);

export const fetchMessages = createAsyncThunk(
  'chat/fetchMessages',
  async ({ receiverId, skip = 0, limit = 50 }, { rejectWithValue }) => {
    try {
      const response = await chatService.getMessages({ receiverId, skip, limit });
      return { messages: response.data.data || [], skip, receiverId };
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to load messages');
    }
  }
);

export const sendTextMessage = createAsyncThunk(
  'chat/sendText',
  async ({ receiverId, message }, { rejectWithValue }) => {
    try {
      const response = await chatService.sendMessage({ receiverId, textMessage: message });
      return response.data.data || response.data;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to send message');
    }
  }
);

export const sendMediaMessage = createAsyncThunk(
  'chat/sendMedia',
  async ({ receiverId, file, messageType }, { rejectWithValue }) => {
    try {
      const formData = new FormData();
      formData.append('receiverId', receiverId);
      formData.append('mediaFile', file);
      formData.append('messageType', messageType); // image, video, audio
      const response = await chatService.sendMedia(formData);
      return response.data.data || response.data;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to send media');
    }
  }
);

export const markChatRead = createAsyncThunk(
  'chat/markRead',
  async ({ recipientId }, { rejectWithValue }) => {
    try {
      await chatService.readChat({ recipientId, updatedAt: new Date().toISOString() });
      return recipientId;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to mark read');
    }
  }
);

export const deleteChatMessage = createAsyncThunk(
  'chat/deleteMessage',
  async ({ messageId }, { rejectWithValue }) => {
    try {
      await chatService.deleteChat({ messageId });
      return messageId;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to delete message');
    }
  }
);

export const fetchUnreadCount = createAsyncThunk(
  'chat/fetchUnread',
  async (_, { rejectWithValue }) => {
    try {
      const response = await chatService.getUnreadCount({});
      return response.data.data || response.data || 0;
    } catch (error) {
      return rejectWithValue(0);
    }
  }
);
