import { createSlice } from '@reduxjs/toolkit';
import {
  fetchMyGroups, fetchDiscoverGroups, createGroup, deleteGroup,
  fetchGroupDetails, fetchGroupPosts, createGroupPost,
  fetchGroupMembers, leaveGroup, joinGroup, updateGroup,
} from '../thunks/groupThunks';

const initialState = {
  myGroups: [],
  discoverGroups: [],
  currentGroup: null,
  groupPosts: [],
  groupMembers: [],
  hasMorePosts: true,
  loading: false,
  postsLoading: false,
  error: null,
};

const groupSlice = createSlice({
  name: 'groups',
  initialState,
  reducers: {
    resetGroups: () => initialState,
    clearCurrentGroup: (state) => {
      state.currentGroup = null;
      state.groupPosts = [];
      state.groupMembers = [];
      state.hasMorePosts = true;
    },
  },
  extraReducers: (builder) => {
    // My groups
    builder
      .addCase(fetchMyGroups.pending, (state) => { state.loading = true; })
      .addCase(fetchMyGroups.fulfilled, (state, action) => {
        state.loading = false;
        state.myGroups = action.payload;
      })
      .addCase(fetchMyGroups.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    // Discover groups
    builder
      .addCase(fetchDiscoverGroups.fulfilled, (state, action) => {
        state.discoverGroups = action.payload;
      });

    // Create group
    builder
      .addCase(createGroup.pending, (state) => { state.loading = true; })
      .addCase(createGroup.fulfilled, (state) => { state.loading = false; })
      .addCase(createGroup.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    // Delete group
    builder
      .addCase(deleteGroup.fulfilled, (state, action) => {
        const groupId = action.payload;
        state.myGroups = state.myGroups.filter((g) =>
          (g._id || g.groupId) !== groupId
        );
      });

    // Leave group
    builder
      .addCase(leaveGroup.fulfilled, (state, action) => {
        const groupId = action.payload;
        state.myGroups = state.myGroups.filter((g) =>
          (g._id || g.groupId) !== groupId
        );
      });

    // Join group
    builder
      .addCase(joinGroup.fulfilled, (state, action) => {
        const groupId = action.payload;
        state.discoverGroups = state.discoverGroups.filter((g) =>
          (g._id || g.groupId) !== groupId
        );
      });

    // Group details
    builder
      .addCase(fetchGroupDetails.fulfilled, (state, action) => {
        state.currentGroup = action.payload;
      });

    // Group posts
    builder
      .addCase(fetchGroupPosts.pending, (state) => { state.postsLoading = true; })
      .addCase(fetchGroupPosts.fulfilled, (state, action) => {
        state.postsLoading = false;
        const { posts, skip } = action.payload;
        if (skip === 0) {
          state.groupPosts = posts;
        } else {
          state.groupPosts = [...state.groupPosts, ...posts];
        }
        state.hasMorePosts = posts.length >= 25;
      })
      .addCase(fetchGroupPosts.rejected, (state) => { state.postsLoading = false; });

    // Create group post
    builder
      .addCase(createGroupPost.fulfilled, (state, action) => {
        if (action.payload) {
          state.groupPosts = [action.payload, ...state.groupPosts];
        }
      });

    // Group members
    builder
      .addCase(fetchGroupMembers.fulfilled, (state, action) => {
        state.groupMembers = action.payload;
      });

    // Update group
    builder
      .addCase(updateGroup.fulfilled, (state, action) => {
        const { groupId, name, description } = action.payload;
        state.myGroups = state.myGroups.map((g) => {
          if ((g._id || g.groupId) === groupId) {
            return { ...g, groupName: name, description };
          }
          return g;
        });
        if (state.currentGroup && (state.currentGroup._id || state.currentGroup.groupId) === groupId) {
          state.currentGroup = { ...state.currentGroup, groupName: name, description };
        }
      });
  },
});

export const { resetGroups, clearCurrentGroup } = groupSlice.actions;
export default groupSlice.reducer;
