import { nodeApi, dotnetApi, dotnetClientApi } from '../axios';
import { ENDPOINTS } from '../config';

const groupService = {
  createGroup: (data) => nodeApi.post(ENDPOINTS.CREATE_GROUP, data),
  createPrivateGroup: (data) => dotnetApi.post(ENDPOINTS.SUBMIT_PRIVATE_GROUP, data),
  getGroupList: (data) => dotnetClientApi.post(ENDPOINTS.GET_GROUP_LIST, data),
  getDiscoverGroups: (params) => dotnetApi.get(ENDPOINTS.GET_GROUPS, { params }),
  submitJoinRequest: (data) => dotnetApi.post(ENDPOINTS.SUBMIT_GROUP_REQUEST, data),
  getJoinRequests: (params) => dotnetApi.get(ENDPOINTS.GET_GROUP_REQUEST, { params }),
  processJoinRequest: (data) => dotnetApi.post(ENDPOINTS.PROCESS_GROUP_REQUEST, data),
  deleteGroup: (data) => nodeApi.post(ENDPOINTS.DELETE_GROUP, data),
  getGroupMembers: (data) => nodeApi.post(ENDPOINTS.GET_GROUP_MEMBERS, data),
  addMember: (data) => nodeApi.post(ENDPOINTS.ADD_MEMBER, data),
  deleteMember: (data) => nodeApi.post(ENDPOINTS.DELETE_MEMBER, data),
  leftGroup: (data) => nodeApi.post(ENDPOINTS.LEFT_GROUP, data),
  createGroupPost: (formData) => nodeApi.post(ENDPOINTS.CREATE_GROUP_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getGroupPosts: (params) => nodeApi.get(ENDPOINTS.GET_GROUP_POSTS, { params }),
  getGroupDetails: (params) => nodeApi.get(ENDPOINTS.GET_GROUP_DETAILS, { params }),
  updateGroup: (data) => dotnetApi.post(ENDPOINTS.UPDATE_GROUP, data),
  addGroupAdmin: (data) => dotnetApi.post(ENDPOINTS.ADD_GROUP_ADMIN, data),
  pauseGroup: (data) => dotnetApi.post(ENDPOINTS.PAUSE_GROUP, data),
  updateGroupIcon: (formData) => nodeApi.post(ENDPOINTS.UPDATE_GROUP_ICON, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
};

export default groupService;
