import { createSlice } from '@reduxjs/toolkit';
import {
  fetchFeedPosts, fetchMyPosts, fetchUserPosts,
  createPost, editPost, deletePost, likeUnlikePost,
  fetchComments, addComment, deleteComment,
} from '../thunks/postThunks';

const initialState = {
  feedPosts: [],
  myPosts: [],
  userPosts: [],
  comments: {},
  loading: false,
  feedLoading: false,
  hasMoreFeed: true,
  hasMoreMine: true,
  hasMoreUser: true,
  error: null,
};

const toggleLike = (posts, postId) => {
  return posts.map((p) => {
    if (p._id === postId) {
      const wasLiked = p.isLike;
      return {
        ...p,
        isLike: !wasLiked,
        totalLike: wasLiked ? Math.max(0, (p.totalLike || 1) - 1) : (p.totalLike || 0) + 1,
      };
    }
    return p;
  });
};

const postSlice = createSlice({
  name: 'posts',
  initialState,
  reducers: {
    resetPosts: () => initialState,
    clearUserPosts: (state) => {
      state.userPosts = [];
      state.hasMoreUser = true;
    },
  },
  extraReducers: (builder) => {
    // Feed posts
    builder
      .addCase(fetchFeedPosts.pending, (state, action) => {
        state.feedLoading = true;
      })
      .addCase(fetchFeedPosts.fulfilled, (state, action) => {
        const { posts, skip } = action.payload;
        state.feedLoading = false;
        if (skip === 0) {
          state.feedPosts = posts;
        } else {
          state.feedPosts = [...state.feedPosts, ...posts];
        }
        state.hasMoreFeed = posts.length >= 20;
      })
      .addCase(fetchFeedPosts.rejected, (state, action) => {
        state.feedLoading = false;
        state.error = action.payload;
      });

    // My posts
    builder
      .addCase(fetchMyPosts.fulfilled, (state, action) => {
        const { posts, skip } = action.payload;
        if (skip === 0) {
          state.myPosts = posts;
        } else {
          state.myPosts = [...state.myPosts, ...posts];
        }
        state.hasMoreMine = posts.length >= 20;
      });

    // User posts
    builder
      .addCase(fetchUserPosts.fulfilled, (state, action) => {
        const { posts, skip } = action.payload;
        if (skip === 0) {
          state.userPosts = posts;
        } else {
          state.userPosts = [...state.userPosts, ...posts];
        }
        state.hasMoreUser = posts.length >= 20;
      });

    // Create post
    builder
      .addCase(createPost.pending, (state) => {
        state.loading = true;
      })
      .addCase(createPost.fulfilled, (state, action) => {
        state.loading = false;
        if (action.payload) {
          state.feedPosts = [action.payload, ...state.feedPosts];
          state.myPosts = [action.payload, ...state.myPosts];
        }
      })
      .addCase(createPost.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      });

    // Edit post
    builder
      .addCase(editPost.fulfilled, (state, action) => {
        const updated = action.payload;
        if (updated) {
          const updateList = (list) => list.map((p) => p._id === updated._id ? { ...p, ...updated } : p);
          state.feedPosts = updateList(state.feedPosts);
          state.myPosts = updateList(state.myPosts);
        }
      });

    // Delete post
    builder
      .addCase(deletePost.fulfilled, (state, action) => {
        const postId = action.payload;
        state.feedPosts = state.feedPosts.filter((p) => p._id !== postId);
        state.myPosts = state.myPosts.filter((p) => p._id !== postId);
        state.userPosts = state.userPosts.filter((p) => p._id !== postId);
      });

    // Like/unlike — optimistic
    builder
      .addCase(likeUnlikePost.pending, (state, action) => {
        const { postId } = action.meta.arg;
        state.feedPosts = toggleLike(state.feedPosts, postId);
        state.myPosts = toggleLike(state.myPosts, postId);
        state.userPosts = toggleLike(state.userPosts, postId);
      })
      .addCase(likeUnlikePost.rejected, (state, action) => {
        // Revert on failure
        const { postId } = action.meta.arg;
        state.feedPosts = toggleLike(state.feedPosts, postId);
        state.myPosts = toggleLike(state.myPosts, postId);
        state.userPosts = toggleLike(state.userPosts, postId);
      });

    // Comments
    builder
      .addCase(fetchComments.fulfilled, (state, action) => {
        const { postId, comments, skip } = action.payload;
        if (skip === 0) {
          state.comments[postId] = comments;
        } else {
          state.comments[postId] = [...(state.comments[postId] || []), ...comments];
        }
      })
      .addCase(addComment.fulfilled, (state, action) => {
        const { postId, comment } = action.payload;
        if (comment) {
          state.comments[postId] = [comment, ...(state.comments[postId] || [])];
          // Update comment count
          const updateCount = (list) => list.map((p) =>
            p._id === postId ? { ...p, totalComment: (p.totalComment || 0) + 1 } : p
          );
          state.feedPosts = updateCount(state.feedPosts);
          state.myPosts = updateCount(state.myPosts);
          state.userPosts = updateCount(state.userPosts);
        }
      })
      .addCase(deleteComment.fulfilled, (state, action) => {
        const { commentId, postId } = action.payload;
        if (state.comments[postId]) {
          state.comments[postId] = state.comments[postId].filter((c) => c._id !== commentId);
        }
        const updateCount = (list) => list.map((p) =>
          p._id === postId ? { ...p, totalComment: Math.max(0, (p.totalComment || 1) - 1) } : p
        );
        state.feedPosts = updateCount(state.feedPosts);
        state.myPosts = updateCount(state.myPosts);
        state.userPosts = updateCount(state.userPosts);
      });
  },
});

export const { resetPosts, clearUserPosts } = postSlice.actions;
export default postSlice.reducer;
