export const loadProfile = createAsyncThunk(
  'auth/loadProfile',
  async (_, { rejectWithValue }) => {
    try {
      const response = await nodeApi.get(ENDPOINTS.GET_PROFILE);
      return response.data.data;
    } catch (error) {
      return rejectWithValue(
        error.response?.data?.message || 'Failed to load profile.'
      );
    }
  }
);

export const logoutUser = createAsyncThunk(
  'auth/logout',
  async (_, { rejectWithValue }) => {
    try {
      await nodeApi.post(ENDPOINTS.LOGOUT);
    } catch (error) {
      // Logout locally even if server call fails
    }
    disconnectSocket();
    localStorage.removeItem('friendlinq_token');
    localStorage.removeItem('friendlinq_user');
    return null;
  }
);
